cd /tmp && cat > StackAllocNint.cs << 'EOF'
using System;

class Program
{
    static void Main()
    {
        Span<nint> nints = stackalloc nint[5];
        for (int i = 0; i < nints.Length; i++)
            nints[i] = i * 10;

        foreach (var val in nints)
            Console.WriteLine(val);

        Span<nuint> nuints = stackalloc nuint[3];
        nuints[0] = 42;
        Console.WriteLine($"nuint[0] = {nuints[0]}");
        Console.WriteLine($"nint size: {sizeof(nint)} bytes");
    }
}
EOF
